phase1.code:
fun main() {
    // ---- if as a statement (Java style) ----
    val age = 20
    var status = ""
    if (age >= 18) {
        status = "Adult"
    } else {
        status = "Minor"
    }
    println("Status: $status")

    // ---- if as an expression (Kotlin style) ----
    val age2 = 20
    val status2 = if (age2 >= 18) "Adult" else "Minor"
    println("Status: $status2")

    // ---- Multiple conditions ----
    val score = 85
    val grade = if (score >= 90) "A"
                else if (score >= 80) "B"
                else if (score >= 70) "C"
                else if (score >= 60) "D"
                else "F"
    println("Grade: $grade")

    // ---- Complex expression ----
    val temperature = 25
    val weather = if (temperature > 30) "Hot"
                  else if (temperature > 20) "Warm"
                  else if (temperature > 10) "Cool"
                  else "Cold"
    println("Weather: $weather")

    // ---- Using if expression in templates ----
    val isEven = 42
    println("42 is ${if (isEven % 2 == 0) "even" else "odd"}")

    // ---- if with blocks ----
    val max = if (10 > 20) {
        println("10 is greater")
        10
    } else {
        println("20 is greater")
        20
    }
    println("Max: $max")

    // ---- Returning from function ----
    fun isAdult(age: Int): Boolean = if (age >= 18) true else false
    println("Is 20 adult? ${isAdult(20)}")
    println("Is 16 adult? ${isAdult(16)}")
}

